def get_odd_collatz(n):
    def collatz_sequence(n):
        while n != 1:
            yield n
            if n % 2 == 0:
                n = n // 2
            else:
                n = 3 * n + 1
        yield 1

    odd_numbers = [num for num in collatz_sequence(n) if num % 2 != 0]
    return sorted(odd_numbers)

