def tri(n):
    if n == 0:
        return [1]
    elif n == 1:
        return [1, 3]

    # Initialize the list with the first two values
    tribonacci = [1, 3]

    for i in range(2, n + 1):
        if i % 2 == 0:
            tribonacci.append(1 + i // 2)
        else:
            # Calculate tri(n + 1) using the formula for even numbers
            next_value = 1 + (i + 1) // 2
            tribonacci.append(tribonacci[-1] + tribonacci[-2] + next_value)

    return tribonacci

def check_if_last_char_is_a_letter(txt):
    # Check if the string is empty or contains only spaces
    if not txt or txt.isspace():
        return False

    # Get the last non-space character and its position
    last_non_space_index = len(txt) - 1
    while last_non_space_index >= 0 and txt[last_non_space_index].isspace():
        last_non_space_index -= 1

    # If the entire string is just spaces, return False
    if last_non_space_index < 0:
        return False

    # Check if the last non-space character is a letter
    last_char = txt[last_non_space_index]
    if not last_char.isalpha():
        return False

    # Check if the last non-space character is not part of a word
    if (last_non_space_index == 0 or txt[last_non_space_index - 1].isspace()) and (last_non_space_index == len(txt) - 1 or txt[last_non_space_index + 1].isspace()):
        # Check if the last non-space character is the only letter in the string
        if all(not c.isalpha() for i, c in enumerate(txt) if i != last_non_space_index):
            return True
        else:
            return False
    else:
        return False

