import defusedxml.sax
from xml.sax.handler import ContentHandler

class ConfigHandler(ContentHandler):
    def __init__(self):
        self.root = None
        self.current = None

    # Call when an element starts
    def startElement(self, tag, attributes):
        if self.current is None:
            self.current = {"tag": tag, "children": []}
        else:
            new_element = {"tag": tag, "children": []}
            self.current["children"].append(new_element)
            self.current = new_element

    # Call when an element ends
    def endElement(self, tag):
        if self.current["tag"] == tag:
            if self.root is None:
                self.root = self.current
            self.current = self.current.get("parent", None)

    # Call when a character is read
    def characters(self, content):
        if self.current is not None:
            self.current["content"] = content.strip()

def get_root():
    '''
    Create an XML parser,
    parse the file 'resources/config.xml' and return the parsed result.
    '''
    handler = ConfigHandler()
    parser = defusedxml.sax.make_parser()
    parser.setContentHandler(handler)
    parser.parse('resources/config.xml')
    return handler.root

